import 'package:flutter/material.dart';import 'package:provider/provider.dart';import 'package:uuid/uuid.dart';import '../../design_system/app_colors.dart';import '../../design_system/app_spacing.dart';import '../../design_system/app_typography.dart';import '../../design_system/ds_buttons.dart';import '../../design_system/ds_input_field.dart';import '../../design_system/ds_toggle_switch.dart';import '../../models/budget.dart';import '../../models/category.dart';import '../../providers/insights_provider.dart';import '../../services/mock_data_service.dart';import 'category_selector_screen.dart';class CreateEditBudgetScreen extends StatefulWidget {  final Budget? budget;  const CreateEditBudgetScreen({super.key, this.budget});  @override  State<CreateEditBudgetScreen> createState() => _CreateEditBudgetScreenState();}@overrideclass _CreateEditBudgetScreenState extends State<CreateEditBudgetScreen> {  final _formKey = GlobalKey<FormState>();  late TextEditingController _nameController;  late TextEditingController _amountController;  List<Category> _selectedCategories = [];  BudgetFrequency _selectedFrequency = BudgetFrequency.monthly;  bool _rolloverOverspend = false;  double _alertThreshold = 0.8;  @override  void initState() {    super.initState();    _nameController = TextEditingController(text: widget.budget?.name ?? '');    _amountController =        TextEditingController(text: widget.budget?.totalAmount.toStringAsFixed(2) ?? '');    _selectedCategories = widget.budget?.categories ?? [];    _selectedFrequency = widget.budget?.frequency ?? BudgetFrequency.monthly;    _rolloverOverspend = widget.budget?.rolloverOverspend ?? false;    _alertThreshold = widget.budget?.alertThreshold ?? 0.8;  }  @override  void dispose() {    _nameController.dispose();    _amountController.dispose();    super.dispose();  }  Future<void> _selectCategories() async {    final result = await Navigator.of(context).push<CategorySelectorScreenResult>(      MaterialPageRoute(builder: (_) => const CategorySelectorScreen()),    );    if (result != null && result.category != null) {      setState(() {        if (!_selectedCategories.contains(result.category)) {          _selectedCategories.add(result.category!);        }      });    }  }  void _saveBudget() {    if (_formKey.currentState!.validate()) {      final String name = _nameController.text;      final double amount = double.parse(_amountController.text);      if (_selectedCategories.isEmpty) {        ScaffoldMessenger.of(context).showSnackBar(          const SnackBar(content: Text('Please select at least one category.')),        );        return;      }      final newBudget = (widget.budget ?? Budget(        id: const Uuid().v4(),        spentAmount: 0.0,        startDate: DateTime.now(),      )).copyWith(        name: name,        totalAmount: amount,        categories: _selectedCategories,        frequency: _selectedFrequency,        rolloverOverspend: _rolloverOverspend,        alertThreshold: _alertThreshold,      );      final insightsProvider = Provider.of<InsightsProvider>(context, listen: false);      if (widget.budget == null) {        insightsProvider.addBudget(newBudget);        ScaffoldMessenger.of(context).showSnackBar(          const SnackBar(content: Text('Budget created successfully!')),        );      } else {        insightsProvider.updateBudget(newBudget);        ScaffoldMessenger.of(context).showSnackBar(          const SnackBar(content: Text('Budget updated successfully!')),        );      }      Navigator.of(context).pop();    }  }  void _deleteBudget() {    if (widget.budget != null) {      Provider.of<InsightsProvider>(context, listen: false)          .deleteBudget(widget.budget!.id);      ScaffoldMessenger.of(context).showSnackBar(        const SnackBar(content: Text('Budget deleted.')),      );      Navigator.of(context).pop(); // Pop from detail screen      Navigator.of(context).pop(); // Pop from edit screen    }  }  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: AppColors.background,      appBar: AppBar(        title: Text(          widget.budget == null ? 'Create New Budget' : 'Edit Budget',          style: AppTypography.h2,        ),      ),      body: Form(        key: _formKey,        child: ListView(          padding: AppSpacing.screenPadding,          children: [            DsInputField(              labelText: 'Budget Name',              hintText: 'e.g., Monthly Dining',              controller: _nameController,              validator: (value) {                if (value == null || value.isEmpty) {                  return 'Please enter a budget name.';                }                return null;              },            ),            SizedBox(height: AppSpacing.paddingMedium),            DsInputField(              labelText: 'Budget Amount',              hintText: 'e.g., 500.00',              controller: _amountController,              keyboardType: TextInputType.number,              validator: (value) {                if (value == null || value.isEmpty) {                  return 'Please enter an amount.';                }                if (double.tryParse(value) == null) {                  return 'Please enter a valid number.';                }                return null;              },            ),            SizedBox(height: AppSpacing.paddingMedium),            _buildCategorySelector(),            SizedBox(height: AppSpacing.paddingMedium),            _buildFrequencySelector(),            SizedBox(height: AppSpacing.paddingMedium),            _buildToggleOption(              'Rollover Savings/Overspend',              _rolloverOverspend,              (value) => setState(() => _rolloverOverspend = value),            ),            SizedBox(height: AppSpacing.paddingMedium),            _buildAlertThresholdSlider(),            SizedBox(height: AppSpacing.paddingLarge),            DsPrimaryButton(              text: widget.budget == null ? 'Save Budget' : 'Update Budget',              onPressed: _saveBudget,            ),            if (widget.budget != null) ...[              SizedBox(height: AppSpacing.paddingSmall),              DsSecondaryButton(                text: 'Delete Budget',                onPressed: _deleteBudget,              ),            ],          ],        ),      ),    );  }  Widget _buildCategorySelector() {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Padding(          padding: const EdgeInsets.only(bottom: AppSpacing.paddingSmall / 2),          child: Text(            'Categories',            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),        ),        Wrap(          spacing: AppSpacing.paddingSmall,          runSpacing: AppSpacing.paddingSmall,          children: [            ..._selectedCategories.map((category) => Chip(                  label: Text(category.name),                  backgroundColor: category.color.withOpacity(0.2),                  labelStyle: AppTypography.caption.copyWith(color: category.color),                  deleteIcon: Icon(Icons.close, size: 18, color: category.color),                  onDeleted: () {                    setState(() {                      _selectedCategories.remove(category);                    });                  },                )),            ActionChip(              label: Text('Add Category'),              avatar: Icon(Icons.add, color: AppColors.primary),              backgroundColor: AppColors.surface,              labelStyle: AppTypography.caption.copyWith(color: AppColors.primary),              onPressed: _selectCategories,            ),          ],        ),      ],    );  }  Widget _buildFrequencySelector() {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Padding(          padding: const EdgeInsets.only(bottom: AppSpacing.paddingSmall / 2),          child: Text(            'Frequency',            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),        ),        Container(          decoration: BoxDecoration(            color: AppColors.surface,            borderRadius: BorderRadius.circular(AppSpacing.borderRadiusSmall),            border: Border.all(color: AppColors.inputBorder),          ),          child: DropdownButtonFormField<BudgetFrequency>(            value: _selectedFrequency,            decoration: InputDecoration(              border: InputBorder.none,              contentPadding: AppSpacing.inputPadding,              isDense: true,            ),            dropdownColor: AppColors.surface,            style: AppTypography.inputField,            iconEnabledColor: AppColors.textSecondary,            onChanged: (BudgetFrequency? newValue) {              if (newValue != null) {                setState(() {                  _selectedFrequency = newValue;                });              }            },            items: BudgetFrequency.values.map((BudgetFrequency frequency) {              return DropdownMenuItem<BudgetFrequency>(                value: frequency,                child: Text(                  frequency.toString().split('.').last.capitalize(),                  style: AppTypography.inputField,                ),              );            }).toList(),          ),        ),      ],    );  }  Widget _buildToggleOption(String title, bool value, ValueChanged<bool> onChanged) {    return Row(      mainAxisAlignment: MainAxisAlignment.spaceBetween,      children: [        Text(title, style: AppTypography.body),        DsToggleSwitch(          value: value,          onChanged: onChanged,        ),      ],    );  }  Widget _buildAlertThresholdSlider() {    return Column(      crossAxisAlignment: CrossAxisAlignment.start,      children: [        Padding(          padding: const EdgeInsets.only(bottom: AppSpacing.paddingSmall / 2),          child: Text(            'Alert Threshold: ${(_alertThreshold * 100).toInt()}% spent',            style: AppTypography.body.copyWith(color: AppColors.textSecondary),          ),        ),        Slider(          value: _alertThreshold,          min: 0.1,          max: 0.9,          divisions: 8,          activeColor: AppColors.primary,          inactiveColor: AppColors.inputBorder,          onChanged: (value) {            setState(() {              _alertThreshold = value;            });          },        ),      ],    );  }}extension StringExtension on String {  String capitalize() {    return "${this[0].toUpperCase()}${substring(1)}";  }}